final:
module top_module(
    input clk,
    input shift,
    input [3:0] D,
    output reg Q3
);reg [3:0] shadow_reg;

always @(posedge clk) begin
    if (shift == 1'b0) begin
        shadow_reg <= D;
    end else begin
        shadow_reg <= {shadow_reg[2:0], D[3]};
    end
end

assign Q3 = shadow_reg[3];

endmodule
